#include <bits/stdc++.h>
using namespace std;
int n,s[11],b[11];
int pro=1,sum,ans=1e9;
bool ch;
void dfs(int x){
    if(ch)
        ans=min(ans,abs(pro-sum));
    if(x>n)
        return;
    dfs(x+1);
    bool last=ch;
    pro*=s[x],sum+=b[x],ch=true;
    dfs(x+1);
    pro/=s[x],sum-=b[x],ch=last;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&s[i],&b[i]);
    dfs(1);
    printf("%d",ans);
    return 0;
}
